use std::collections::BTreeSet;

fn solve(c: i64, connections: Vec<Vec<i64>>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let c_usize = c as usize;
    let mut graph: Vec<Vec<usize>> = vec![vec![]; c_usize + 1];

    for conn in &connections {
        let u = conn[0] as usize;
        let v = conn[1] as usize;
        graph[u].push(v);
        graph[v].push(u);
    }

    let mut comp_id: Vec<i32> = vec![-1; c_usize + 1];
    let mut visited = vec![false; c_usize + 1];
    let mut comp_count = 0;

    for i in 1..=c_usize {
        if !visited[i] {
            let mut stack = vec![i];
            visited[i] = true;
            comp_id[i] = comp_count as i32;

            while let Some(node) = stack.pop() {
                for &neighbor in &graph[node] {
                    if !visited[neighbor] {
                        visited[neighbor] = true;
                        comp_id[neighbor] = comp_count as i32;
                        stack.push(neighbor);
                    }
                }
            }

            comp_count += 1;
        }
    }

    let mut comp_sets: Vec<BTreeSet<i64>> = vec![BTreeSet::new(); comp_count];
    let mut is_online = vec![true; c_usize + 1];

    for i in 1..=c_usize {
        let comp_index = comp_id[i] as usize;
        comp_sets[comp_index].insert(i as i64);
    }

    let mut result = Vec::new();

    for query in &queries {
        let t = query[0];
        let x_val = query[1];
        let x = x_val as usize;

        if t == 1 {
            if is_online[x] {
                result.push(x_val);
            } else {
                let comp_index = comp_id[x] as usize;
                if let Some(min_node) = comp_sets[comp_index].iter().next().copied() {
                    result.push(min_node);
                } else {
                    result.push(-1);
                }
            }
        } else if t == 2 {
            if is_online[x] {
                is_online[x] = false;
                let comp_index = comp_id[x] as usize;
                comp_sets[comp_index].remove(&x_val);
            }
        }
    }

    result
}
```

### Explanation
1. **Graph Construction**: The graph is built using an adjacency list where each node points to its connected neighbors.
2. **Component Identification**: Using iterative DFS, each node is processed to determine its connected component. Nodes in the same component share the same component ID.
3. **Component Sets**: For each component, a BTreeSet is used to store node IDs in sorted order. This allows efficient access to the smallest online node.
4. **Query Handling**:
   - **Maintenance Query (Type 1)**: Directly returns the node if online; otherwise, it retrieves the smallest online node from its component's set. Returns -1 if no nodes are online.
   - **Offline Operation (Type 2)**: Marks the node as offline and removes it from its component's set.
5. **Efficiency**: The use of BTreeSet ensures logarithmic time complexity for insertions, deletions, and min element retrievals, making the solution scalable for large inputs as specified in the problem constraints. The DFS preprocessing is linear in the number of nodes and edges, ensuring overall efficiency.

To solve this problem, we need to efficiently handle two types of queries on a network of power stations connected by bidirectional cables. The stations can be online (operational) or offline (non-operational). The queries involve either checking a station's status or turning a station offline, and for status checks, we need to determine the smallest online station in the same network if the queried station is offline.

### Approach
1. **Graph Construction**: Represent the stations and their connections as an undirected graph using an adjacency list.
2. **Connected Components Identification**: Use BFS to traverse the graph and identify connected components. Each station is assigned a component ID indicating which network it belongs to.
3. **Component Tracking**: For each connected component, maintain a `BTreeSet` to keep track of online stations in sorted order. This allows efficient retrieval of the smallest online station in the component.
4. **Online Status Tracking**: Maintain a boolean array to track the online status of each station.
5. **Query Processing**:
   - **Type 1 Query (Check Status)**: If the station is online, the result is the station itself. If offline, the smallest online station in its component is retrieved from the `BTreeSet`. If no online stations exist in the component, return -1.
   - **Type 2 Query (Turn Offline)**: If the station is online, update its status to offline and remove it from the component's `BTreeSet`.

